import sqlite3

db = sqlite3.connect(':memory:')

def login(user, passwd):
    q = "SELECT * FROM users WHERE username='" + user + "' AND password='" + passwd + "'"
    return db.execute(q).fetchone()

def search(term):
    return db.execute(f"SELECT * FROM items WHERE name LIKE '%{term}%'").fetchall()

def get_by_id(item_id):
    return db.execute("SELECT * FROM items WHERE id = ?", (item_id,)).fetchone()

def update_stock(item_id, qty):
    db.execute("UPDATE items SET stock = %d WHERE id = %d" % (qty, item_id))
    db.commit()

def insert_safe(name, price):
    db.execute("INSERT INTO items (name, price) VALUES (?, ?)", (name, price))
    db.commit()

def delete_item(name):
    db.execute("DELETE FROM items WHERE name = '{}'".format(name))
    db.commit()

